    parentName: "p"
  }, "'\uB0B4\uAC00 \uB098\uB97C \uD1B5\uC81C\uD558\uC9C0 \uBABB\uD568'"), "\uC744 \uC758\uBBF8\uD558\uAC8C \uB429\uB2C8\uB2E4.\n\uC774\uB807\uAC8C \uC0DD\uAC01\uC744 \uD558\uB2C8 \uC644\uBCBD \uC8FC\uC758\uC801 \uC131\uACA9\uC744 \uAC00\uC9C4 \uC81C \uB9C8\uC74C\uC774 \uB9E4\uC6B0 \uD3B8\uC548\uD574\uC84C\uC2B5\uB2C8\uB2E4.\n\uD56D\uC0C1 \uC774\uAC8C \uAC00\uB2A5\uD55C \uC0AC\uB78C\uC740 \uC5C6\uC73C\uB2C8, '\uC838\uB3C4 \uB41C\uB2E4. \uC5F0\uD328\uB9CC \uD558\uC9C0 \uB9D0\uB77C' \uB294 \uC0DD\uAC01\uC774 \uC2A4\uD2B8\uB798\uC2A4 \uBD80\uD558\uB97C \uB9CE\uC774 \uC904\uC5EC\uC8FC\uB294 \uAC83 \uAC19\uC558\uC5B4\uC694."), mdx("h3", null, "\uC5B4\uB5BB\uAC8C \uD574\uC57C \uC2B9\uB9AC\uD560\uAE4C"), mdx("p", null, "\uADF8\uB807\uB2E4\uBA74 \uC5B4\uB5BB\uAC8C \uD574\uC57C \uB0B4\uAC00 \uB098\uB97C \uC774\uAE38 \uC218 \uC788\uC744\uAE4C\uC694?"), mdx("p", null, "\uC804\uB7B5\uC744 \uC138\uC6B0\uAE30 \uC55E\uC11C \uB1CC\uACFC\uD559\uACFC \uAD00\uB828\uB41C \uC774\uC57C\uAE30\uB97C \uC870\uAE08 \uD574\uC57C\uACA0\uC2B5\uB2C8\uB2E4."), mdx("p", null, "\uC6B0\uB9AC\uC758 \uB1CC\uC758 \uD3B8\uB3C4\uCCB4\uC640 \uBCC0\uC5F0\uACC4\uB294 '\uB180\uACE0 \uC2F6\uB2E4'\uB294 \uC0DD\uAC01\uC744 \uD558\uAC8C \uB9CC\uB4ED\uB2C8\uB2E4. \uADF8\uB9AC\uACE0 \uC774 \uAC10\uC815\uC801\uC778 \uC0DD\uAC01\uC744 \uC774\uC131\uC801\uC73C\uB85C \uB9C9\uC544\uC8FC\uB294 \uAC83\uC774 \uC548\uC640\uC804\uB450\uD53C\uC9C8\uC785\uB2C8\uB2E4.\n\uC548\uC640\uC804\uB450\uD53C\uC9C8\uC774 \uB9CE\uC774 \uBC1C\uB2EC\uD558\uC9C0 \uC54A\uC740 \uC0AC\uB78C\uC740 \uCDA9\uB3D9\uC801\uC774\uACE0, \uC790\uAE30 \uC870\uC808 \uB2A5\uB825\uC774 \uB5A8\uC5B4\uC9D1\uB2C8\uB2E4.\n\uADF8\uB7EC\uB098 \uC548\uC640\uC804\uB450\uD53C\uC9C8\uC740 \uD6C4\uCC9C\uC801\uC73C\uB85C \uBC1C\uB2EC\uC2DC\uD0AC \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uADF8\uB9AC\uACE0, '\uC5B8\uC5B4'\uC744 \uD1B5\uD574 \uC548\uC640\uC804\uB450\uD53C\uC9C8\uC758 \uD798\uC744 \uAC15\uD558\uAC8C \uB9CC\uB4E4 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4.\n\uC0DD\uAC01\uC744 \uC5B8\uC5B4\uB85C \uB9D0\uD560 \uB54C \uC548\uC640\uC804\uB450 \uD53C\uC9C8\uC774 \uD65C\uC131\uD654\uB418\uAE30 \uB54C\uBB38\uC785\uB2C8\uB2E4."), mdx("p", null, "\uC989, '\uB180\uACE0 \uC2F6\uB2E4'\uB77C\uB294 \uC0DD\uAC01\uC774 \uB4E4\uC5C8\uC744 \uB54C, '\uC544\uAE4C \uB180\uC558\uC73C\uB2C8 \uC774\uB9CC \uCDA9\uBD84\uD55C \uAC83 \uAC19\uC740\uB370?' \uB77C\uACE0 \uC785 \uBC16\uC73C\uB85C \uB0B4\uBC49\uC73C\uBA74 \uC704\uAE30\uB97C \uBAA8\uBA74\uD558\uAE30\uAC00 \uD6E8\uC52C \uC26C\uC6CC\uC9D1\uB2C8\uB2E4."), mdx("p", null, "\uC5B8\uC5B4\uAC00 \uC778\uAC04\uC758 \uC0DD\uAC01\uC744 \uACAC\uC778\uD55C\uB2E4\uB2C8, \uCC38\uC73C\uB85C \uC778\uAC04\uC758 \uB1CC\uB294 \uC2E0\uBE44\uD558\uACE0 \uBA4B\uC9C0\uB2E4\uB294 \uC0DD\uAC01\uC744 \uD588\uC2B5\uB2C8\uB2E4."), mdx("h3", null, "\uC5F0\uD328\uB294 \uC8FD\uC5B4\uB3C4 \uC548\uD574"), mdx("p", null, "\uC800\uB294 \uB2E4\uC774\uC5B4\uB9AC\uC5D0 \uC2B9\uB9AC\uD55C \uB0A0\uACFC \uD328\uBC30\uD55C \uB0A0\uC744 \uAE30\uB85D\uD569\uB2C8\uB2E4."), mdx("p", null, "\uB2E8\uC21C\uD788 \uB0A0\uC9DC\uC5D0 \uB3D9\uADF8\uB77C\uBBF8\uB97C \uCE58\uBA74 \uC2B9\uB9AC\uD55C \uB0A0\uC774\uACE0, X\uD45C\uB97C \uCE58\uBA74 \uD328\uBC30\uD55C \uB0A0\uC774\uB77C\uB294 \uC2DD\uC785\uB2C8\uB2E4.\n\uADF8 \uBC11\uC5D0\uB294 \uC870\uADF8\uB9E3\uAC8C \uB098\uC640\uC758 \uC5B4\uB5A4 \uB0B4\uAE30\uC5D0\uC11C \uC2B9\uB9AC\uD588\uB294\uC9C0\uB97C \uC801\uC5B4\uC694."), mdx("p", null, "'\uC5F0\uD328\uB294 \uC8FD\uC5B4\uB3C4 \uC548\uD574'\uB77C\uB294 \uC0DD\uAC01\uC73C\uB85C \uB2E4\uC774\uC5B4\uB9AC\uB97C \uBCF4\uB2E4 \uBCF4\uBA74, \uADF8 \uD6A8\uACFC\uB97C \uAF64\uB098 \uC2E4\uAC10\uD558\uAC8C \uB429\uB2C8\uB2E4."), mdx("p", null, "\uADF8 \uB3D9\uC548 \uBAA8\uC784\uC7A5 \uAC19\uC740 \uD658\uACBD\uC124\uC815\uC744 \uD1B5\uD574 \uD68C\uD53C \uB3D9\uAE30\uB97C \uB9CC\uB4E0\uB2E4\uB358\uC9C0 \uC5EC\uB7EC\uAC00\uC9C0 \uBC29\uBC95\uC744 \uC368\uBD24\uC9C0\uB9CC \uC18C\uC6A9\uC774 \uC5C6\uC5C8\uB358 \uC0AC\uB78C\uC73C\uB85C\uC368 \uC81C\uAC8C \uB9DE\uB294 \uBC29\uBC95\uC744 \uB4DC\uB514\uC5B4 \uCC3E\uC740 \uAC83 \uAC19\uC544 \uAE30\uC069\uB2C8\uB2E4."));
